from __future__ import annotations
from dataclasses import dataclass
from typing import Optional


@dataclass
class ControlEffect:
    # A single control and its estimated score-reduction factor.
    control_id: str
    name: str
    reduction_factor: float  # fraction reduction applied to composite score (0.0-1.0)
    validated: bool = True   # False if control defined but not yet operational


@dataclass
class RiskWithControls:
    base_entry: RiskEntry
    controls: list[ControlEffect]

    def residual_score(self) -> float:
        # Multiplicative reduction: residual = inherent * (1-r1) * (1-r2) ...
        score = float(self.base_entry.inherent_score)
        for ctrl in self.controls:
            if ctrl.validated:
                score *= (1.0 - ctrl.reduction_factor)
        return round(score, 1)

    def residual_zone(self) -> RiskZone:
        return risk_zone(round(self.residual_score()))

    def control_gap(self) -> float:
        # Positive gap means controls are reducing risk as expected.
        return round(self.base_entry.inherent_score - self.residual_score(), 1)

    def open_controls(self) -> list[ControlEffect]:
        # Controls defined but not yet validated.
        return [c for c in self.controls if not c.validated]


rwc = RiskWithControls(
    base_entry=entry,
    controls=[
        ControlEffect('CTRL-001', 'Output grounding to approved product list', 0.40, validated=True),
        ControlEffect('CTRL-002', 'Human-in-loop review for regulated advice', 0.30, validated=True),
        ControlEffect('CTRL-003', 'Real-time hallucination classifier',        0.20, validated=False),
    ],
)
print(rwc.residual_score())  # 9 * 0.60 * 0.70 = 3.78 -> low zone
print(rwc.control_gap())     # 5.22
print([c.control_id for c in rwc.open_controls()])  # ['CTRL-003']
